'use strict';

// MODULES //

var resolve = require( 'path' ).resolve;
var remark = require( 'remark' );
var logger = require( 'debug' );
var visit = require( 'unist-util-visit' );
var readFileSync = require( '@stdlib/fs/read-file' ).sync;
var format = require( '@stdlib/string/format' );


// VARIABLES //

var debug = logger( 'remark-includes:transformer' );
var INCLUDE_START = /<!--\s*<include\s+path="([^"]*)">\s*-->/;
var INCLUDE_END = /<!--\s*<\/include>\s*-->/;


// MAIN //

/**
* Returns a transformer function.
*
* @private
* @param {Options} opts - transformer options
* @param {(string|null)} opts.dir - base directory for resolving include paths
* @returns {Function} transformer function
*/
function factory( opts ) {
	var parser;

	parser = remark();
	return transformer;

	/**
	* Transforms a Markdown abstract syntax tree (AST) by inserting content from external files.
	*
	* @private
	* @param {Node} tree - root node of the AST
	* @param {File} file - virtual file
	*/
	function transformer( tree, file ) {
		debug( 'Processing virtual file: %s', file.path );
		visit( tree, 'html', visitor );
		debug( 'Finished processing virtual file.' );

		/**
		* Callback invoked upon finding an HTML node.
		*
		* @private
		* @param {Node} node - AST node
		* @param {number} index - position of `node` in `parent`
		* @param {Node} parent - parent of `node`
		*/
		function visitor( node, index, parent ) {
			var children;
			var content;
			var fpath;
			var match;
			var base;
			var end;
			var c;
			var i;

			match = INCLUDE_START.exec( node.value );
			if ( match === null ) {
				return;
			}
			debug( 'Found an include directive: %s', match[ 1 ] );

			// Resolve the file path:
			if ( opts.dir === null ) {
				base = file.dirname;
			} else {
				base = opts.dir;
			}
			if ( base === void 0 || base === null ) {
				debug( 'Missing base directory for include path: %s', match[ 1 ] );
				file.message( format( 'unable to resolve include path due to missing base directory: %s', match[ 1 ] ), node );
				return;
			}
			fpath = resolve( base, match[ 1 ] );
			debug( 'Resolved include path: %s', fpath );

			// Read the file:
			content = readFileSync( fpath, {
				'encoding': 'utf8'
			});
			if ( content instanceof Error ) {
				debug( 'Unable to resolve include: %s. Error: %s', fpath, content.message );
				file.message( format( 'unable to resolve include: %s', fpath ), node );
				return;
			}
			debug( 'Successfully read include file.' );

			// Find the matching closing tag by scanning subsequent siblings:
			end = -1;
			for ( i = index + 1; i < parent.children.length; i++ ) {
				if (
					parent.children[ i ].type === 'html' &&
					INCLUDE_END.test( parent.children[ i ].value )
				) {
					end = i;
					break;
				}
			}
			if ( end === -1 ) {
				debug( 'Missing closing include comment for: %s', match[ 1 ] );
				file.message( format( 'missing closing include comment for: %s', match[ 1 ] ), node );
				return;
			}
			debug( 'Found closing include comment at index: %d', end );

			// Parse the included Markdown content into AST nodes:
			children = parser.parse( content ).children;
			debug( 'Parsed %d nodes from include file.', children.length );

			// Remove existing nodes between the opening and closing tags:
			parent.children.splice( index + 1, end - index - 1 );

			// Insert the parsed nodes between the opening and closing tags:
			c = parent.children;
			c.splice.apply( c, [ index + 1, 0 ].concat( children ) );
			debug( 'Inserted include content.' );
		}
	}
}


// EXPORTS //

module.exports = factory;
